SELECT AVG(min_order_quantity) AS avg_min_order_quantity
FROM cryptocurrency_pairs
WHERE base_currency = 'OP';

SELECT pair_name 
FROM cryptocurrency_pairs 
WHERE max_order_amount > 5000.0;

SELECT pair_name 
FROM cryptocurrency_pairs 
WHERE pair_id = 1;

SELECT AVG(price) AS average_price
FROM market_data
WHERE pair_id = (SELECT pair_id FROM cryptocurrency_pairs WHERE pair_name = 'OP/ETH');

SELECT SUM(value) AS total_value
FROM portfolio
WHERE user_id = (
  SELECT user_id FROM users WHERE user_name = 'Alice Johnson'
);
